import { describe, it, expect, vi, beforeEach } from 'vitest'
import { mount, flushPromises } from '@vue/test-utils'
import { createPinia, setActivePinia } from 'pinia'
import TaskFilters from '@/components/TaskFilters.vue'

vi.mock('@/api/tasks', () => ({
  fetchTasks: vi.fn().mockResolvedValue({
    content: [],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
  }),
  createTask: vi.fn(),
}))

describe('TaskFilters', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  function mountFilters() {
    return mount(TaskFilters, {
      global: {
        plugins: [createPinia()],
      },
    })
  }

  // AC2: Has search input for keyword
  it('should render a search input', () => {
    const wrapper = mountFilters()
    const input = wrapper.find('input[type="text"], input[type="search"]')
    expect(input.exists()).toBe(true)
  })

  // AC3: Has priority dropdown with All/HIGH/MEDIUM/LOW options
  it('should render a priority dropdown with correct options', () => {
    const wrapper = mountFilters()
    const selects = wrapper.findAll('select')
    // Find priority select - it should have HIGH/MEDIUM/LOW options
    const prioritySelect = selects.find((s) => {
      const options = s.findAll('option')
      return options.some((o) => o.text().includes('HIGH') || o.element.value === 'HIGH')
    })
    expect(prioritySelect).toBeTruthy()
    const options = prioritySelect!.findAll('option')
    const values = options.map((o) => o.element.value)
    expect(values).toContain('HIGH')
    expect(values).toContain('MEDIUM')
    expect(values).toContain('LOW')
    // Should have an "All" option (value = '' or null)
    expect(options.length).toBeGreaterThanOrEqual(4)
  })

  // AC4: Has status dropdown with All/TODO/IN_PROGRESS/DONE/CLOSED options
  it('should render a status dropdown with correct options', () => {
    const wrapper = mountFilters()
    const selects = wrapper.findAll('select')
    const statusSelect = selects.find((s) => {
      const options = s.findAll('option')
      return options.some((o) => o.text().includes('TODO') || o.element.value === 'TODO')
    })
    expect(statusSelect).toBeTruthy()
    const options = statusSelect!.findAll('option')
    const values = options.map((o) => o.element.value)
    expect(values).toContain('TODO')
    expect(values).toContain('IN_PROGRESS')
    expect(values).toContain('DONE')
    expect(values).toContain('CLOSED')
    // Should have an "All" option
    expect(options.length).toBeGreaterThanOrEqual(5)
  })

  // AC2 + BR3: Keyword input triggers store setKeyword with debounce
  it('should call store.setKeyword after debounce on input', async () => {
    const wrapper = mountFilters()
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    const setKeywordSpy = vi.spyOn(store, 'setKeyword')
    const fetchTasksSpy = vi.spyOn(store, 'fetchTasks')

    const input = wrapper.find('input[type="text"], input[type="search"]')
    await input.setValue('test keyword')

    // Should not call immediately (debounce)
    expect(setKeywordSpy).not.toHaveBeenCalled()

    // After debounce (300ms)
    vi.advanceTimersByTime(300)
    await flushPromises()

    expect(setKeywordSpy).toHaveBeenCalledWith('test keyword')
  })

  // AC3: Priority dropdown change calls setPriorityFilter + fetchTasks
  it('should call store.setPriorityFilter on priority change', async () => {
    const wrapper = mountFilters()
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    const spy = vi.spyOn(store, 'setPriorityFilter')

    const selects = wrapper.findAll('select')
    const prioritySelect = selects.find((s) => {
      const options = s.findAll('option')
      return options.some((o) => o.text().includes('HIGH') || o.element.value === 'HIGH')
    })

    await prioritySelect!.setValue('HIGH')
    await flushPromises()

    expect(spy).toHaveBeenCalledWith('HIGH')
  })

  // AC4: Status dropdown change calls setStatusFilter + fetchTasks
  it('should call store.setStatusFilter on status change', async () => {
    const wrapper = mountFilters()
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    const spy = vi.spyOn(store, 'setStatusFilter')

    const selects = wrapper.findAll('select')
    const statusSelect = selects.find((s) => {
      const options = s.findAll('option')
      return options.some((o) => o.text().includes('TODO') || o.element.value === 'TODO')
    })

    await statusSelect!.setValue('IN_PROGRESS')
    await flushPromises()

    expect(spy).toHaveBeenCalledWith('IN_PROGRESS')
  })
})

